local TestShared = require("shared")
local BridgeBuilder = require("__enemyracemanager__/lib/bridge_builder")
local SurfaceProcessor = require("__enemyracemanager__/lib/surface_processor")
local ForceHelper = require("__enemyracemanager__/lib/helper/force_helper")


before_each(function()
    TestShared.prepare_the_factory()
end)

after_each(function()
    TestShared.reset_the_factory()
end)

describe("Bridge Builder", function()
    it("Can create bridge", function()
        async(1800)
        local surface = game.surfaces[1]
        -- Require generated chunks
        surface.request_to_generate_chunks({ 0, 0 }, 20)
        surface.force_generate_chunk_requests()

        TestShared.buildBaseNoOpen()
        BridgeBuilder.exec(surface, { x=0,y=-300 }, { x=0,y=0 })
        after_ticks(1800, function()
            assert( surface.get_tile(0, -180).name == 'sand-1', "Should able to build bridge")
            done()
        end)
    end)

    it("Can not create bridge with void tile", function()
        async(1800)
        local surface = game.surfaces[1]
        -- Require generated chunks
        surface.request_to_generate_chunks({ 0, 0 }, 20)
        surface.force_generate_chunk_requests()

        TestShared.buildBaseNoOpen()
        for x = -10, 10, 1 do
            for y = -195, -170, 1 do
                surface.set_tiles {{ name = "out-of-map", position = { x, y } }}
            end
        end
        BridgeBuilder.exec(surface, { x=0,y=-300 }, { x=0,y=0 })
        after_ticks(1800, function()
            assert( surface.get_tile(0, -180).name ~= 'sand-1', "Should not able to build bridge")
            done()
        end)
    end)
    
    it("Test surface ignore", function()
        async(1800)
        local nauvis = game.surfaces['nauvis']
        local map_gen = nauvis.map_gen_settings
        local surfaceA = game.create_surface('test_bridge_builder_surface', map_gen)
        SurfaceProcessor.register_external_planet({
            surface = surfaceA
        })
        ForceHelper.reset_surface_from_lists(surfaceA.name)
        SurfaceProcessor.register_enemies(surfaceA)
        surfaceA.request_to_generate_chunks({ 0, 0 }, 20)
        surfaceA.force_generate_chunk_requests()
        TestShared.buildBaseNoOpen({surface=surfaceA})
        BridgeBuilder.exec(surfaceA, { x=0,y=-300 }, { x=0,y=0 })
        after_ticks(1800, function()
            assert( surfaceA.get_tile(0, -180).name == 'water', "Should not able to build bridge")
            done()
        end)
    end)
    
end)